select mb.*, m.name, m.internal_id, m.model, m.color, mc.name category from jsh_material_bom mb left join jsh_material_extend me on mb.bar_code=me.bar_code and ifnull(me.delete_Flag,'0') !='1' left join jsh_material m on m.id=me.material_id and ifnull(m.delete_Flag,'0') !='1' left JOIN jsh_material_category mc on m.category_id = mc.id and ifnull(mc.delete_Flag,'0') !='1' where 1=1
and mb.process like #{bindProcess}
and lower(mb.project) like lower(#{bindProject})
and (mb.bar_code like #{bindKey} or m.name like #{bindKey} or m.internal_id like #{bindKey} or m.model like #{bindKey})
and m.category_id in
#{item}
and ifnull(mb.delete_flag,'0') !='1' order by mb.id desc
limit #{offset},#{rows}

select mb.*, m.name, me.material_id materialId, m.internal_id, m.model, m.color, me.id meId, mc.name category from jsh_material_bom mb left join jsh_material_extend me on mb.bar_code=me.bar_code and ifnull(me.delete_Flag,'0') !='1' left join jsh_material m on m.id=me.material_id and ifnull(m.delete_Flag,'0') !='1' left JOIN jsh_material_category mc on m.category_id = mc.id and ifnull(mc.delete_Flag,'0') !='1' where me.bar_code in (
#{barCode}
) and ifnull(mb.delete_flag,'0') !='1' group by me.bar_code order by mb.process asc

